FROM players pl 
JOIN persons per ON pl.person_id = per.id 
WHERE per.first_name = 'Nile' AND per.last_name = 'Williams' 
ON CONFLICT (source_system_id, external_id) DO UPDATE SET
  team_external_id = EXCLUDED.team_external_id;

